// src/types.ts
var TokenResolutionError = class extends Error {
  constructor(message, variableId, variableName, context) {
    super(message);
    this.variableId = variableId;
    this.variableName = variableName;
    this.context = context;
    this.name = "TokenResolutionError";
  }
};
var CircularReferenceError = class extends TokenResolutionError {
  constructor(variableId, chain) {
    super(
      `Circular reference detected in variable ${variableId}: ${chain.join(" -> ")}`,
      variableId
    );
    this.name = "CircularReferenceError";
  }
};
var UnresolvedTokenError = class extends TokenResolutionError {
  constructor(variableId, variableName, context) {
    super(
      `Token "${variableName || variableId}" could not be resolved`,
      variableId,
      variableName,
      context
    );
    this.name = "UnresolvedTokenError";
  }
};

